import React from "react";
import { Link as ScrollLink } from "react-scroll"; // Rename import to avoid confusion
import { Link as RouterLink, useLocation } from "react-router-dom";
import "../styles/Navbar.css";

const Navbar = () => {
  const location = useLocation();

  // Function to handle navigation based on the current route
  const handleNavClick = (section) => {
    if (location.pathname === "/") {
      // If already on home page, scroll smoothly
      ScrollLink.scrollTo(section, { smooth: true, duration: 500 });
    } else {
      // Navigate to home page first, then scroll
      window.location.href = `/#${section}`;
    }
  };

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <ScrollLink to="HOME" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </ScrollLink>
      </div>
      <ul className="navbar-links">
        {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
          <li key={section}>
            <button 
              onClick={() => handleNavClick(section)} 
              className="nav-button"
            >
              {section.replace(/^\w/, (c) => c.toUpperCase()).replace("-", " ")}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
